import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: 'your-vex-key' });

const command = new InvokeAgentCommand({
  agentId: 'YOUR_AGENT_ID',
  agentAliasId: 'YOUR_ALIAS_ID',
  sessionId: 'legal-session-123',
  inputText: 'Summarize contract risks for client ACME Corp',
});

const response = await bedrock.send(command);
const completion = response.completion;

// Vex legal verification
const result = await vex.verify({
  prompt: 'Summarize contract risks for client ACME Corp',
  completion,
  policy: 'legal-bedrock-agent',
  context: {
    domain: 'legal',
    pii_scan: true,
    citation_validation: true,
    require_attorney_review: true
  }
});

if (result.status === 'BLOCK') {
  console.log('BLOCKED: ' + result.reason);
  // Add attorney review workflow
}
